{
  "intent": "check_and_fix",
  "intent_description": "R2 Serial0/1/1 moved to oper-state lower-layer-down while admin up; R3 Serial0/1/1 is administratively down (oper down). Goal: restore the serial link to operational up state.",
  "target": "R2,R3",
  "needs_fix": true,
  "plan": {
    "problem": "R2 Serial0/1/1 oper=lower-layer-down, admin=up; R3 Serial0/1/1 oper=down, admin=down. The remote end (R3) is administratively down, preventing the link from coming up.",
    "fix_summary": "Bring R3 Serial0/1/1 admin state to up (no shutdown) to restore the link. If the link does not return to up, perform an interface bounce on R2 Serial0/1/1 (shutdown then no shutdown). Risk: bouncing R2 interface will cause a brief outage on that link.",
    "plan_steps": [
      {
        "id": 1,
        "device": "router3",
        "action": "set_interface_admin_state",
        "target": "Serial0/1/1",
        "parameters": [
          "up"
        ]
      },
      {
        "id": 2,
        "device": "router2",
        "action": "set_interface_admin_state",
        "target": "Serial0/1/1",
        "parameters": [
          "down"
        ]
      },
      {
        "id": 3,
        "device": "router2",
        "action": "set_interface_admin_state",
        "target": "Serial0/1/1",
        "parameters": [
          "up"
        ]
      }
    ]
  }
}
